var e=[{id:`L2_1`,type:`dialog`,speaker:`SPIRA_CORRUPT_NULL_SHADE`,text:{KOREA:`전부......! 죽여 버리겠어어어어!`,JPN:`全部……！　殺してやるうううぅぅぅぅ！！`,ENG:`I'll... kill you all!`,TWN:`全部……！殺掉！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`SPIRA_CORRUPT_NULL_SHADE`,face:`UNIT_HATE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`아윽......!`,JPN:`あうッ……！`,ENG:`Ugh!`,TWN:`啊呃……！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`어쩌지? 계속 싸웠는데 조금도 약해지지 않았어......!`,JPN:`どうしよう……あれだけ攻撃したのに全然弱っていない……！`,ENG:`What should I do? She hasn't grown weak at all, even after all that fighting!`,TWN:`怎麼辦？打了這麼久，她怎麼還這麼有力氣……！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`제길, 구경만 하지 마! 꼬마를 엄호해!`,JPN:`くそっ、何をボーっとしてるんだ！　チビを援護しろ！`,ENG:`Come on, don't just watch! Give the kid some covering fire!`,TWN:`可惡，別光看著！掩護她！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`PMC_NPC_TYPEA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`PMC_NPC_TYPEA_NULL`,text:{KOREA:`안 돼, 대장! 적이 너무 빨라서 조준할 수가 없어!`,JPN:`ダメだ、隊長！　敵が速すぎて照準を合わせられない！`,ENG:`We can't, Captain! The target's too fast to aim at!`,TWN:`不行，隊長！敵人太快了，根本沒辦法瞄準！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`PMC_NPC_TYPEA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L14_1`,type:`dialog`,speaker:`PMC_NPC_TYPEA_NULL`,text:{KOREA:`우리만으론 역부족이야! 차라리 내가 가서 그 여자를 찾아 올게!`,JPN:`俺たちだけじゃ力不足だ！　俺があの女を連れてくる！`,ENG:`We can't do this by ourselves! Let me just go find that woman instead!`,TWN:`光靠我們不行！我去找那個女人！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`PMC_NPC_TYPEA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`이 겁쟁이 자식! 도망치려고 핑계 대는 거지?!`,JPN:`この臆病め！　ただの逃げる口実だろ！？`,ENG:`You coward! You're just looking for an excuse to get away, aren't you?`,TWN:`這個膽小鬼！你是為逃跑找藉口吧？！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`PMC_NPC_TYPEA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`꺄악!?`,JPN:`きゃあっ！？`,ENG:`Eeek!`,TWN:`哎喲！？`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`안 돼! 저러다 꼬마가 당하겠어!`,JPN:`ダメだ、あのままじゃチビがやられちまう！`,ENG:`No! The kid's in danger!`,TWN:`不行！這樣下去那個孩子會受傷的！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`SPIRA_CORRUPT_NULL_SHADE`,text:{KOREA:`아아아아아아아아아───────────!!`,JPN:`アアアアアアァァァァァ───────────！！`,ENG:`AAAAAAAAHHHHHHHHHHHHHHH!`,TWN:`啊啊啊啊啊啊啊啊啊！！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`SPIRA_CORRUPT_NULL_SHADE`,face:`UNIT_HATE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`SPIRA_CORRUPT_NULL_SHADE`,text:{KOREA:`커흑......?!`,JPN:`くっ……！？`,ENG:`Ack?!`,TWN:`呼唔……？！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`SPIRA_CORRUPT_NULL_SHADE`,face:`UNIT_SURPRISE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`PMC_NPC_TYPEA_NULL`,text:{KOREA:`화살......?!`,JPN:`矢……！？`,ENG:`Arrows?`,TWN:`箭……？！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`PMC_NPC_TYPEA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L31_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`저기 봐! 그 사채업자야!`,JPN:`あそこだ！　あの闇金業者だ！`,ENG:`Look! It's the loan shark lady!`,TWN:`看那邊！是那個放高利貸的！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`PMC_NPC_TYPEA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L33_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`갑자기 뒤가 시끄럽길래 돌아왔더니...... 이건 또 무슨 난장판이지?`,JPN:`急に後ろが騒がしいから戻ってきたら……これはどういう状況だ？`,ENG:`I turned around to see what the commotion was about... What the hell is going on here?`,TWN:`我說這裡怎麼亂哄哄的……現在這是在鬧哪一齣？`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`RITA_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L36_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`리타 언니! 안 오면 어쩌나 걱정하고 있었어요!`,JPN:`リタお姉ちゃん！　来てくれなかったらどうしようと思ってました！`,ENG:`Rita! I was getting worried you might not show up!`,TWN:`麗塔姐姐！我還擔心你不來怎麼辦呢！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`RITA_HORIZON_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};